const alertId = $workflow.input.alert_id;
const evidenceBundle = $workflow.input.evidence_bundle;
const agentOutput = $workflow.input.agent_output;
if (!alertId) throw new Error('VALIDATION_ERROR: alert_id is required');
if (!Array.isArray(evidenceBundle)) throw new Error('VALIDATION_ERROR: evidence_bundle must be an array');
if (!agentOutput || !Array.isArray(agentOutput.citations)) throw new Error('VALIDATION_ERROR: agent_output.citations must be an array');
const bundleIds = new Set(evidenceBundle.map(function(e) { return e.evidence_id; }));
const RISK_TIER_MAP = { 'low': 0, 'medium': 1, 'high': 2 };
const RECOMMENDATION_MAP = { 'escalate': 0, 'close': 1 };
const validatedCitations = agentOutput.citations.map(function(cid) {
  const isVerified = bundleIds.has(cid);
  return { evidence_id: cid, outcome: isVerified ? 'verified' : 'unverified_flagged', check_outcome_number_id: isVerified ? 0 : 1 };
});
const hasUnverified = validatedCitations.some(function(c) { return c.outcome === 'unverified_flagged'; });
const riskTierLower = (agentOutput.risk_tier || 'medium').toLowerCase();
const recommendationLower = (agentOutput.recommendation || 'close').toLowerCase();
const proposedRiskTierNumberId = RISK_TIER_MAP[riskTierLower] !== undefined ? RISK_TIER_MAP[riskTierLower] : 1;
const recommendationNumberId = RECOMMENDATION_MAP[recommendationLower] !== undefined ? RECOMMENDATION_MAP[recommendationLower] : 0;
return { validated_citations: validatedCitations, has_unverified: hasUnverified, proposed_risk_tier_number_id: proposedRiskTierNumberId, recommendation_number_id: recommendationNumberId, confidence: agentOutput.confidence || 0, rationale: agentOutput.rationale || '', cited_evidence_ids_json: JSON.stringify(agentOutput.citations) };

const cr = $context.outputs.CreateEntityRecordCurated_AgentAssessment;
const id = (cr && cr.content && cr.content.Id !== undefined) ? cr.content.Id : (cr && cr.content && cr.content.id !== undefined) ? cr.content.id : '';
return id;

const bundle = $workflow.input.evidence_bundle;
const results = [];
for (let i = 0; i < bundle.length; i++) {
  const item = bundle[i];
  if (item.category === 'screening') {
    let payload;
    try { payload = typeof item.payload === 'string' ? JSON.parse(item.payload) : item.payload; } catch(e) { continue; }
    if (payload && payload.sanctions_match) {
      const match = payload.sanctions_match;
      const entity = match.entity || 'unknown';
      const role = match.role || 'counterparty';
      results.push({ kind: 'sanctions', detail: 'Sanctions-list match on ' + role + ' ' + entity });
    }
  }
}
return results;

const bundle = $workflow.input.evidence_bundle;
const results = [];
for (let i = 0; i < bundle.length; i++) {
  const item = bundle[i];
  if (item.category === 'screening') {
    let payload;
    try { payload = typeof item.payload === 'string' ? JSON.parse(item.payload) : item.payload; } catch(e) { continue; }
    if (payload && payload.pep_match) {
      const match = payload.pep_match;
      const name = match.name || match.entity || 'unknown';
      results.push({ kind: 'pep', detail: 'Politically-exposed-person match on ' + name });
    }
  }
}
return results;

const bundle = $workflow.input.evidence_bundle;
const results = [];
const txItems = [];
for (let i = 0; i < bundle.length; i++) {
  const item = bundle[i];
  if (item.category === 'transaction_history') {
    let payload;
    try { payload = typeof item.payload === 'string' ? JSON.parse(item.payload) : item.payload; } catch(e) { continue; }
    if (payload && Array.isArray(payload.transactions)) {
      for (let t = 0; t < payload.transactions.length; t++) { txItems.push(payload.transactions[t]); }
    }
  }
}
const inBand = [];
for (let i = 0; i < txItems.length; i++) {
  const tx = txItems[i];
  const amt = parseFloat(tx.amount_myr || tx.amount || 0);
  if (amt >= 22500 && amt < 25000) {
    const d = new Date(tx.date).getTime();
    if (!isNaN(d)) { inBand.push({ date: d, dateStr: tx.date }); }
  }
}
inBand.sort(function(a, b) { return a.date - b.date; });
const WINDOW_MS = 7 * 24 * 60 * 60 * 1000;
let firedEntry = null;
for (let i = 0; i < inBand.length && !firedEntry; i++) {
  let j = i;
  while (j < inBand.length && inBand[j].date - inBand[i].date <= WINDOW_MS) { j++; }
  if (j - i >= 3) { firedEntry = { count: j - i, startDate: inBand[i].dateStr, endDate: inBand[j - 1].dateStr }; }
}
if (firedEntry) {
  results.push({ kind: 'structuring', detail: firedEntry.count + ' transactions in [RM22,500, RM25,000) within a 7-day rolling window (' + firedEntry.startDate + '..' + firedEntry.endDate + ')' });
}
return results;

const bundle = $workflow.input.evidence_bundle;
const results = [];
for (let i = 0; i < bundle.length; i++) {
  const item = bundle[i];
  if (item.category === 'screening') {
    let payload;
    try { payload = typeof item.payload === 'string' ? JSON.parse(item.payload) : item.payload; } catch(e) { continue; }
    if (payload && payload.high_risk_jurisdiction) {
      const match = payload.high_risk_jurisdiction;
      const entity = match.entity || match.name || 'unknown';
      results.push({ kind: 'jurisdiction', detail: 'Counterparty ' + entity + ' registered in a high-risk call-to-action jurisdiction' });
    }
  }
}
return results;

const bundle = $workflow.input.evidence_bundle;
const results = [];
for (let i = 0; i < bundle.length; i++) {
  const item = bundle[i];
  if (item.category === 'screening') {
    let payload;
    try { payload = typeof item.payload === 'string' ? JSON.parse(item.payload) : item.payload; } catch(e) { continue; }
    if (payload && payload.watchlist_match) {
      const match = payload.watchlist_match;
      const entity = match.entity || match.name || 'unknown';
      results.push({ kind: 'watchlist', detail: 'Internal watchlist match on ' + entity });
    }
  }
}
return results;

const sanctions = $context.outputs.Javascript_Detect_Sanctions || [];
const pep = $context.outputs.Javascript_Detect_Pep || [];
const structuring = $context.outputs.Javascript_Detect_Structuring || [];
const jurisdiction = $context.outputs.Javascript_Detect_Jurisdiction || [];
const watchlist = $context.outputs.Javascript_Detect_Watchlist || [];
const redFlags = [].concat(sanctions, pep, structuring, jurisdiction, watchlist);
const agentOutput = $workflow.input.agent_output;
const originalProposedTier = (agentOutput.risk_tier || 'medium').toLowerCase();
const confidenceRaw = typeof agentOutput.confidence === 'number' ? agentOutput.confidence : parseFloat(agentOutput.confidence) || 0;
const confidence = (confidenceRaw > 0 && confidenceRaw <= 1) ? confidenceRaw * 100 : confidenceRaw;
let finalRiskTier, tierWasForced, route;
if (redFlags.length > 0) {
  finalRiskTier = 'high';
  tierWasForced = true;
  route = 'high_challenger';
} else if (originalProposedTier === 'low') {
  finalRiskTier = 'low';
  tierWasForced = false;
  route = confidence >= 85 ? 'low_batch' : 'medium_signoff';
} else {
  finalRiskTier = originalProposedTier;
  tierWasForced = false;
  route = 'medium_signoff';
}
return { red_flags: redFlags, final_risk_tier: finalRiskTier, tier_was_forced: tierWasForced, original_proposed_tier: originalProposedTier, route: route };
